class Solution(object):
    def minSizeSubarray(self, nums, target):
        """
        :type nums: List[int]
        :type target: int
        :rtype: int
        """
        n = len(nums)
        prefix_sum = [0] * (n + 1)

        for i in range(n):
            prefix_sum[i + 1] = prefix_sum[i] + nums[i]

        min_length = float('inf')

        for start in range(n):
            required_sum = target + prefix_sum[start]
            low, high = start + 1, n

            while low <= high:
                mid = (low + high) // 2
                if prefix_sum[mid] < required_sum:
                    low = mid + 1
                else:
                    high = mid - 1

            if low <= n and prefix_sum[low] == required_sum:
                min_length = min(min_length, low - start)

        return min_length if min_length != float('inf') else -1